#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    int searchList(ListNode* head, int target) {
        int idx = 0;
        for (ListNode* cur = head; cur != nullptr; cur = cur->next) {
            if (cur->val == target) return idx;
            ++idx;
        }
        return -1;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n);
    for (int i = 0; i < n; ++i) cin >> vals[i];
    int target;
    cin >> target;
    // build linked list
    ListNode* dummy = new ListNode(0);
    ListNode* cur = dummy;
    for (int v : vals) {
        cur->next = new ListNode(v);
        cur = cur->next;
    }
    ListNode* head = dummy->next;
    Solution sol;
    int ans = sol.searchList(head, target);
    cout << ans << "\n";
    // cleanup (optional)
    cur = head;
    while (cur) {
        ListNode* nxt = cur->next;
        delete cur;
        cur = nxt;
    }
    delete dummy;
    return 0;
}
